mapper.select:
select r.id, r.reporter_id as reporter_id, m.nickname as reporter_nickname, r.target_type as target_type, r.target_id as target_id, r.reason, r.detail, r.status, r.resolved_at as resolved_at, r.created_datetime as created_datetime, case when r.target_type = 'WORK' then ( select w.title from tbl_work w where w.id = r.target_id ) when r.target_type = 'MEMBER' then ( select m2.nickname from tbl_member m2 where m2.id = r.target_id ) else 'unknown' end as target_name, ( select count(*) from tbl_report r2 where r2.target_type = r.target_type and r2.target_id = r.target_id ) as target_report_count from tbl_report r join tbl_member m on r.reporter_id = m.id
and ( m.nickname ilike '%' || #{keyword} || '%' or r.detail ilike '%' || #{keyword} || '%' )
and r.target_type = #{targetType}
and r.status = #{status}
and r.reporter_id = #{reporterId}
order by r.created_datetime desc limit #{size} offset (#{page} - 1) * #{size}

select count(*)
from tbl_report r
join tbl_member m on r.reporter_id = m.id


        and (
            m.nickname ilike '%' || #{keyword} || '%'
            or r.detail ilike '%' || #{keyword} || '%'
        )


        and r.target_type = #{targetType}


        and r.status = #{status}


        and r.reporter_id = #{reporterId}
